import pika

# RabbitMQ connection parameters
rabbitmq_host = 'localhost'
rabbitmq_port = 5672
rabbitmq_queue = 'task_queue'

# Establish RabbitMQ connection
connection = pika.BlockingConnection(pika.ConnectionParameters(host=rabbitmq_host, port=rabbitmq_port))
channel = connection.channel()

# Create the task queue
channel.queue_declare(queue=rabbitmq_queue)

# Publisher
def publish_task(task_message):
    channel.basic_publish(exchange='', routing_key=rabbitmq_queue, body=task_message.encode())

# Consumer
def consume_tasks():
    channel.basic_consume(queue=rabbitmq_queue, on_message_callback=process_task)

def process_task(ch, method, properties, body):
    task_message = body.decode()
    # Process the task message here
    print(f"Processing task: {task_message}")
    ch.basic_ack(delivery_tag=method.delivery_tag)

# Start consuming tasks
consume_tasks()

# Run the publisher and consumer indefinitely
try:
    while True:
        # Publish a task message
        task_message = "Process this task"
        publish_task(task_message)
except KeyboardInterrupt:
    pass

# Close RabbitMQ connection
connection.close()